#include <stdio.h>
#include <string.h>
#include <ctype.h>
#include <limits.h>
#include <math.h>
#include <stdlib.h>

int main() {

	int n;
	int a[20] = { 0 };
	int i;
	int chest = 0;
	int back = 0;
	int biceps = 0;

	scanf("%d", &n);
	for (i = 0; i < n; i++) {
		scanf("%d", &a[i]);
	}

	for (i = 0; i < n; i += 3) {
		chest += a[i];
	}
	for (i = 1; i < n; i += 3) {
		biceps += a[i];
	}
	for (i = 2; i < n; i += 3) {
		back += a[i];
	}

	if (chest > biceps && chest > back) {
		printf("chest");
	} else if (biceps > chest && biceps > back) {
		printf("biceps");
	} else if (back > biceps && back > chest) {
		printf("back");
	}

	return 0;
}

